"use client";

import { use, useRef } from "react";
import { motion, type Variants, useScroll, useTransform, useSpring } from "motion/react";
import {
  ArrowLeft,
  CheckCircle2,
  UserCircle,
  Library,
  BookOpen,
  Bus,
  CreditCard,
  FileSpreadsheet,
  Zap,
  Shield,
  Layers,
  Sparkles,
  Users,
  Wallet,
  ClipboardList,
  CalendarCheck,
  ExternalLink,
  Check,
  ChevronDown,
  HelpCircle
} from "lucide-react";
import Image from "next/image";
import Link from "next/link";
import data from "@/data.json";
import { Navbar } from "@/components/landing/Navbar";
import { BackgroundEffects } from "@/components/landing/BackgroundEffects";
import { CtaFooter } from "@/components/landing/CtaFooter";
import { FooterBar } from "@/components/landing/FooterBar";
import { notFound } from "next/navigation";

const iconMap: Record<string, any> = {
  UserCircle,
  Library,
  BookOpen,
  Bus,
  CreditCard,
  FileSpreadsheet,
  Users,
  Wallet,
  ClipboardList,
  CalendarCheck,
  Zap,
  Shield,
  Layers,
  Sparkles,
  Check
};

const fadeUp: Variants = {
  hidden: { opacity: 0, y: 30 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.6, ease: "easeOut" } },
};

const stagger: Variants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.1 } },
};

export default function SolutionDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = use(params);
  const solution = data.solutions.items.find((item) => item.id === id);

  const containerRef = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start 30%", "start start"]
  });

  const smoothProgress = useSpring(scrollYProgress, {
    stiffness: 400,
    damping: 50,
    restDelta: 0.001
  });

  const rotateX = useTransform(smoothProgress, [0, 0.05], [25, 0]);
  const scale = useTransform(smoothProgress, [0, 0.2], [1.05, 1]);
  const translateZ = useTransform(smoothProgress, [0, 0.2], [-100, 0]);
  const opacity = useTransform(smoothProgress, [0, 0.2], [0.95, 1]);

  if (!solution) {
    notFound();
  }

  return (
    <div className="relative min-h-screen flex flex-col bg-zinc-950 text-zinc-50 overflow-hidden">
      <Navbar />
      <BackgroundEffects />

      <main className="relative z-10 flex-1">
        {/* Navigation & Header */}
        <div className="px-6 pt-24 md:pt-32 max-w-7xl mx-auto">
          <Link
            href="/solutions"
            className="inline-flex items-center gap-2 text-zinc-400 hover:text-white transition-colors mb-8 group"
          >
            <ArrowLeft className="w-4 h-4 group-hover:-translate-x-1 transition-transform" />
            <span>Back to Solutions</span>
          </Link>

          <motion.div
            variants={stagger}
            initial="hidden"
            animate="visible"
            className="flex flex-col gap-6"
          >
            <motion.h1
              variants={fadeUp}
              className="text-4xl md:text-6xl font-bold tracking-tight text-white"
            >
              {solution.title}
            </motion.h1>
            <motion.p
              variants={fadeUp}
              className="text-xl text-zinc-400 max-w-3xl leading-relaxed"
            >
              {solution.shortDescription}
            </motion.p>

            {solution.projectUrl && (
              <motion.div variants={fadeUp}>
                <Link
                  href={solution.projectUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="inline-flex items-center gap-2 bg-white text-black px-6 py-3 rounded-full font-bold hover:bg-zinc-200 transition-colors group"
                >
                  <span>Visit Project Website</span>
                  <ExternalLink className="w-4 h-4 group-hover:translate-x-0.5 group-hover:-translate-y-0.5 transition-transform" />
                </Link>
              </motion.div>
            )}
          </motion.div>
        </div>



        {/* Hero Banner */}
        <section ref={containerRef} className="px-6 py-16 max-w-7xl mx-auto [perspective:1500px]">
          <motion.div
            variants={fadeUp}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true }}
            style={{
              rotateX,
              scale,
              translateZ,
              opacity,
              transformStyle: "preserve-3d",
              transformOrigin: "center center"
            }}
            transition={{ duration: 0.8 }}
            className="relative h-[300px] md:h-[600px] rounded-[3rem] md:rounded-[3rem] overflow-hidden border border-white/40 shadow-2xl shadow-white/10"
          >
            <div className="relative w-full h-full bg-zinc-950">
              <Image
                src={solution.image}
                alt={solution.title}
                fill
                className="object-contain md:object-cover"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-white/10 via-transparent to-transparent z-10 pointer-events-none" />
              <div className="absolute inset-0 bg-linear-to-t from-zinc-950 via-transparent to-transparent opacity-60" />
            </div>
          </motion.div>
        </section>

        {/* Detailed Explanation */}
        <section className="px-6 py-24 bg-white/[0.02] border-y border-white/5">
          <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16 items-center">
            <motion.div
              variants={fadeUp}
              initial="hidden"
              whileInView="visible"
              viewport={{ once: true }}
              className="flex flex-col gap-8"
            >
              <h2 className="text-3xl md:text-4xl font-bold text-white leading-tight">
                Empowering Institutions with <span className="text-zinc-400 font-serif italic">Next-Gen Technology</span>
              </h2>
              <div className="space-y-6 text-zinc-400 text-lg leading-relaxed">
                <p>{solution.fullDescription}</p>
              </div>

              <div className="grid grid-cols-2 gap-6 pt-4">
                {[
                  { label: "Cloud-Based", icon: Zap },
                  { label: "Secure Data", icon: Shield },
                  { label: "User Friendly", icon: Layers },
                  { label: "24/7 Support", icon: Sparkles },
                ].map((feature, idx) => (
                  <div key={idx} className="flex items-center gap-3">
                    <div className="p-2 rounded-lg bg-white/5 border border-white/10 text-white">
                      <Check className="w-4 h-4 text-white" />
                    </div>
                    <span className="font-medium text-zinc-200">{feature.label}</span>
                  </div>
                ))}
              </div>
            </motion.div>

            <motion.div
              initial={{ opacity: 0, x: 20 }}
              whileInView={{ opacity: 1, x: 0 }}
              viewport={{ once: true }}
              className="relative aspect-square lg:aspect-auto lg:h-[500px] rounded-[2.5rem] bg-zinc-900 overflow-hidden border border-white/5"
            >
              {/* Decorative elements or secondary image */}
              <div className="absolute inset-0 flex items-center justify-center p-12">
                <div className="w-full h-full rounded-3xl bg-linear-to-br from-zinc-800 to-zinc-950 border border-white/10 shadow-2xl flex items-center justify-center relative group">
                  <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-white/10 via-transparent to-transparent opacity-50" />
                  {/* if solution.title === "Vidyum" */}
                  {solution.title === "Vidyum" ? (
                    <Image src="/Group.png" alt="Vidyum" width={144} height={144} style={{ height: 'auto' }} />
                  ) : (
                    <svg width="776" height="570" viewBox="0 0 776 570" fill="none" xmlns="http://www.w3.org/2000/svg">
                      <rect width="776" height="570" rx="26" fill="white" />
                      <path d="M378.037 44.2895C347.958 46.0388 318.814 55.6782 293.382 72.2901C267.95 88.902 247.075 111.933 232.745 139.191C218.415 166.449 211.107 197.026 211.516 228.011C211.926 258.996 220.04 289.357 235.085 316.204L296.201 279.969C287.169 263.852 282.298 245.626 282.053 227.025C281.807 208.424 286.194 190.067 294.797 173.704C303.399 157.34 315.931 143.514 331.199 133.542C346.466 123.569 363.962 117.782 382.019 116.732L378.037 44.2895Z" fill="#0B1D2D" />
                      <path d="M246.539 334.11C265.536 360.297 291.052 380.725 320.395 393.24L347.415 326.216C329.8 318.703 314.482 306.439 303.078 290.718L246.539 334.11Z" fill="#0B1D2D" />
                      <path d="M468.646 387.027C504.31 368.184 532.673 337.413 549.069 299.779C565.464 262.145 568.913 219.891 558.849 179.972L490.565 198.186C496.607 222.15 494.536 247.516 484.693 270.109C474.851 292.701 457.823 311.174 436.413 322.486L468.646 387.027Z" fill="#0B1D2D" />
                      <path d="M551.982 158.393C539.615 126.442 518.68 98.7614 491.612 78.5732C464.545 58.385 432.459 46.5197 399.091 44.3588L394.658 116.774C414.69 118.071 433.952 125.194 450.201 137.313C466.45 149.433 479.018 166.05 486.443 185.231L551.982 158.393Z" fill="#0B1D2D" />
                      <ellipse cx="388.5" cy="225.5" rx="113" ry="116.5" fill="white" />
                      <path d="M402.354 336H375.269L308.5 526H485.5L402.354 336Z" fill="url(#paint0_linear_341_549)" />
                      <path d="M407.365 316.507C399.516 331.487 377.952 331.487 370.103 316.507L369.733 315.771L345.552 265.242C336.057 245.403 350.519 222.45 372.513 222.45H404.955C426.949 222.45 441.41 245.403 431.916 265.242L407.734 315.771L407.365 316.507Z" fill="#EF7603" stroke="white" stroke-width="27" />
                      <circle cx="389.364" cy="205.693" r="22.6929" fill="#EF7603" />
                      <rect x="252" y="497" width="289" height="57" fill="url(#pattern0_341_549)" />
                      <defs>
                        <pattern id="pattern0_341_549" patternContentUnits="objectBoundingBox" width="1" height="1">
                          <use href="#image0_341_549" transform="matrix(0.00109848 0 0 0.00556948 -0.192234 -4.3907)" />
                        </pattern>
                        <linearGradient id="paint0_linear_341_549" x1="397" y1="336" x2="397" y2="526" gradientUnits="userSpaceOnUse">
                          <stop stop-color="#EF7603" />
                          <stop offset="0.557006" stop-color="white" stop-opacity="0" />
                        </linearGradient>
                        <image id="image0_341_549" width="1254" height="1254" preserveAspectRatio="none" href="data:image/png;base64," />
                      </defs>
                    </svg>

                  )}
                </div>
              </div>
            </motion.div>
          </div>
        </section>

        {/* Modules Grid */}
        <section className="px-6 py-32 max-w-7xl mx-auto">
          <div className="flex flex-col items-center text-center gap-6 mb-20">
            <h2 className="text-4xl md:text-5xl font-bold text-white">
              Comprehensive <span className="font-serif italic text-zinc-400">Modules</span>
            </h2>
            <p className="text-lg text-zinc-400 max-w-2xl">
              Everything you need to manage your institution efficiently in one unified platform.
            </p>
          </div>

          <motion.div
            variants={stagger}
            initial="hidden"
            whileInView="visible"
            viewport={{ once: true }}
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8"
          >
            {solution.modules.map((module, idx) => {
              const Icon = iconMap[module.icon] || CheckCircle2;
              return (
                <motion.div
                  key={idx}
                  variants={fadeUp}
                  className="p-8 rounded-[2rem] bg-zinc-900/50 border border-white/5 hover:border-white/10 hover:bg-zinc-900/80 transition-all group"
                >
                  <div className="w-14 h-14 rounded-2xl bg-white/5 flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-white/10 transition-all">
                    <Icon className="w-7 h-7 text-white" />
                  </div>
                  <h3 className="text-xl font-bold text-white mb-4">{module.title}</h3>
                  <p className="text-zinc-400 leading-relaxed">
                    {module.description}
                  </p>
                </motion.div>
              );
            })}
          </motion.div>
        </section>

        {/* FAQ Section */}
        {solution.faq && (
          <section className="px-6 py-32 max-w-3xl mx-auto">
            <div className="flex flex-col items-center text-center gap-6 mb-16">
              <span className="px-4 py-1.5 rounded-full bg-white/5 border border-white/10 text-xs font-bold tracking-widest text-white uppercase">
                {solution.faq.pill}
              </span>
              <h2 className="text-4xl md:text-5xl font-bold text-white">
                {solution.faq.heading} <span className="font-serif italic text-zinc-400">{solution.faq.headingItalic}</span>
              </h2>
            </div>

            <div className="space-y-4">
              {solution.faq.questions.map((item, idx) => (
                <motion.div
                  key={idx}
                  initial={{ opacity: 0, y: 10 }}
                  whileInView={{ opacity: 1, y: 0 }}
                  viewport={{ once: true }}
                  transition={{ delay: idx * 0.05 }}
                  className="group rounded-3xl border border-white/5 bg-zinc-900/30 overflow-hidden"
                >
                  <details className="w-full">
                    <summary className="flex items-center justify-between p-6 cursor-pointer list-none">
                      <div className="flex items-center gap-4">
                        <HelpCircle className="w-5 h-5 text-zinc-500" />
                        <h3 className="font-bold text-white text-lg">{item.question}</h3>
                      </div>
                      <ChevronDown className="w-5 h-5 text-zinc-500 group-open:rotate-180 transition-transform" />
                    </summary>
                    <div className="px-6 pb-6 pt-0 text-zinc-400 leading-relaxed pl-[3.25rem]">
                      {item.answer}
                    </div>
                  </details>
                </motion.div>
              ))}
            </div>
          </section>
        )}
      </main>

      <CtaFooter />
      <FooterBar />
    </div>
  );
}
